import{_ as o,o as t,c as a,ae as r}from"./chunks/framework.CyZiF_rV.js";const y=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"pl/srodowiska.md","filePath":"pl/srodowiska.md"}'),i={name:"pl/srodowiska.md"};function n(s,e,d,c,w,p){return t(),a("div",null,[...e[0]||(e[0]=[r('<h2 id="srodowiska-ksef-api-2-0" tabindex="-1">Środowiska KSeF API 2.0 <a class="header-anchor" href="#srodowiska-ksef-api-2-0" aria-label="Permalink to &quot;Środowiska KSeF API 2.0&quot;">​</a></h2><p>15.12.2025</p><p>Poniżej zestawiono informacje o publicznych środowiskach.</p><table tabindex="0"><thead><tr><th>Skrót</th><th>Środowisko</th><th>Opis</th><th>Dokumentacja API</th><th>Dopuszczalne formaty</th></tr></thead><tbody><tr><td><strong>TEST</strong></td><td>Testowe <br> (Release Candidate)</td><td>Środowisko do testowania integracji z KSeF API 2.0, zawiera wersje RC.</td><td><a href="https://api-test.ksef.mf.gov.pl/docs/v2" target="_blank" rel="noreferrer">https://api-test.ksef.mf.gov.pl/docs/v2</a></td><td>FA(2), FA(3), FA_PEF (3), FA_KOR_PEF (3)</td></tr><tr><td><strong>DEMO</strong></td><td>Przedprodukcyjne (Demo)</td><td>Środowisko odpowiadające konfiguracji produkcyjnej, przeznaczone do końcowej walidacji integracji w warunkach zbliżonych do produkcji.</td><td><a href="https://api-demo.ksef.mf.gov.pl/docs/v2" target="_blank" rel="noreferrer">https://api-demo.ksef.mf.gov.pl/docs/v2</a></td><td>FA(3), FA_PEF (3), FA_KOR_PEF (3)</td></tr><tr><td><strong>PRD</strong></td><td>Produkcyjne</td><td>Środowisko do wystawiania i odbierania faktur o pełnej mocy prawnej, z gwarantowanym SLA i właściwymi danymi produkcyjnymi.</td><td><a href="https://api.ksef.mf.gov.pl/docs/v2" target="_blank" rel="noreferrer">https://api.ksef.mf.gov.pl/docs/v2</a></td><td>FA(3), FA_PEF (3), FA_KOR_PEF (3)</td></tr></tbody></table><blockquote><p>&lt;font color=&quot;red&quot;&gt;Uwaga:&lt;/font&gt; Środowiska testowe (TE/DEMO) służy wyłącznie do testowania integracji z API KSeF. Nie należy przesyłać do niego <strong>faktur produkcyjnych</strong> ani rzeczywistych danych podmiotów.</p></blockquote><p>W środowisku testowym <code>TE</code> dopuszczalne jest uwierzytelnianie przy użyciu samopodpisanych certyfikatów (self-signed), co w praktyce oznacza, że wielu integratorów może <a href="./uwierzytelnianie.html#proces-uwierzytelniania">uwierzytelnić się</a> w kontekście tej samej firmy. Z tego względu dane wprowadzone w środowisku <code>TE</code> nie są odizolowane i mogą być współdzielone między integratorami. Do testów należy używać losowych identyfikatorów NIP, unikając jakichkolwiek danych rzeczywistych.</p><h3 id="prace-serwisowe-na-srodowiskach-testowych" tabindex="-1">Prace serwisowe na środowiskach testowych <a class="header-anchor" href="#prace-serwisowe-na-srodowiskach-testowych" aria-label="Permalink to &quot;Prace serwisowe na środowiskach testowych&quot;">​</a></h3><p>W związku z planowanym, systematycznym rozwojem Krajowego Systemu e-Faktur (KSeF 2.0), <strong>od dnia 1 października 2025 r.</strong> na środowiskach testowych Systemu mogą być prowadzone cykliczne prace serwisowe.</p><p>Prace te będą realizowane w godzinach od <strong>16:00 do 18:00</strong>. W tym czasie mogą wystąpić przejściowe utrudnienia w dostępie do środowisk testowych.</p><p>Po zakończeniu prac w <a href="./api-changelog.html">changelogu</a> publikowane będą <strong>wyłącznie zmiany mające wpływ na integrację</strong> np. zmiany zachowań API, modyfikacje kontraktów, schematów XSD, limitów itp. Zmiany niewpływające na API i niezauważalne z perspektywy integracji np. wewnętrzne poprawki jakości, wydajności, bezpieczeństwa <strong>mogą nie być komunikowane</strong> lub będą prezentowane zbiorczo.</p>',10)])])}const l=o(i,[["render",n]]);export{y as __pageData,l as default};
